const crypto = require('crypto');

const req = items[0]?.json ?? {};
const headers = req.headers || {};
const body = req.body || {};
const rawBody = typeof req.rawBody === 'string' && req.rawBody.length > 0
  ? req.rawBody
  : JSON.stringify(body);

const secret = $env.PADDLE_WEBHOOK_SECRET || '';
const paddleSig = headers['paddle-signature'] || headers['Paddle-Signature'] || '';

function parseSignatureHeader(sigHeader) {
  const out = {};
  for (const part of String(sigHeader || '').split(';')) {
    const [k, v] = part.split('=');
    if (k && v) out[k.trim()] = v.trim();
  }
  return out;
}

function safeEqualHex(a, b) {
  try {
    const ba = Buffer.from(String(a || ''), 'hex');
    const bb = Buffer.from(String(b || ''), 'hex');
    return ba.length === bb.length && crypto.timingSafeEqual(ba, bb);
  } catch {
    return false;
  }
}

function tryJsonParse(value) {
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}

const sigParts = parseSignatureHeader(paddleSig);
const ts = Number(sigParts.ts || 0);
const h1 = sigParts.h1 || '';
const nowSec = Math.floor(Date.now() / 1000);
const tsFresh = ts > 0 && Math.abs(nowSec - ts) <= 300;

let signatureValid = false;
if (secret && h1 && tsFresh) {
  const signedPayload = `${ts}:${rawBody}`;
  const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');
  signatureValid = safeEqualHex(expected, h1);
}

const eventType = body.event_type || body.eventType || '';
const eventId = String(body.event_id || body.notification_id || body.eventId || '').trim();
const data = body.data || {};

let passthrough = data.passthrough || data.custom_data?.passthrough || '';
if (typeof passthrough === 'string') {
  const parsed = tryJsonParse(passthrough);
  if (parsed && typeof parsed === 'object') passthrough = parsed;
}

const email = (
  data.customer?.email ||
  data.customer_email ||
  data.custom_data?.email ||
  data.custom_data?.user_email ||
  (typeof passthrough === 'object' ? passthrough.email : '') ||
  ''
).toLowerCase().trim();

const statusRaw = String(data.status || '').toLowerCase();
const paidByStatus = ['paid', 'completed', 'billed', 'active'].includes(statusRaw);
const paidByEvent = [
  'transaction.completed',
  'transaction.paid',
  'payment_succeeded',
  'subscription.created',
  'subscription.activated'
].includes(String(eventType || '').toLowerCase());

const amountRaw =
  data.details?.totals?.total ||
  data.totals?.total ||
  data.amount ||
  data.earnings ||
  null;
// Paddle Billing v2 returns totals in smallest currency unit (cents); divide by 100
const amountParsed = amountRaw == null ? null : Number(String(amountRaw).replace(',', '.'));
const paidAmount = Number.isFinite(amountParsed) ? +(amountParsed / 100).toFixed(2) : null;

const transactionId = String(data.id || data.transaction_id || data.order_id || '').trim();
const customerId = String(data.customer_id || data.customer?.id || '').trim();
const paymentDate = data.billed_at || data.created_at || body.occurred_at || new Date().toISOString();

const shouldProcess = Boolean(secret && signatureValid && email && (paidByStatus || paidByEvent));

return [{
  json: {
    should_process: shouldProcess,
    event_id: eventId,
    reason: shouldProcess
      ? 'verified_paid_event'
      : 'ignored_event_or_invalid_signature',
    event_type: eventType,
    email,
    paid_amount: Number.isFinite(paidAmount) ? paidAmount : null,
    transaction_id: transactionId,
    customer_id: customerId,
    payment_date: paymentDate,
    signature_present: Boolean(paddleSig),
    signature_valid: signatureValid
  }
}];

const paidLead = $('Mark Lead as Paid').first().json || {};
const rawProfile = paidLead.user_profile;
let userProfile = {};

if (rawProfile && typeof rawProfile === 'object') {
  userProfile = rawProfile;
} else if (typeof rawProfile === 'string' && rawProfile.trim()) {
  try {
    const parsed = JSON.parse(rawProfile);
    userProfile = parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    userProfile = {};
  }
}

return [{
  json: {
    user_profile: userProfile,
    email: String(paidLead.email || ''),
    name: String(paidLead.name || '')
  }
}];

