const planData = $('Generate Program').first().json;
const normalized = $('Normalize User Profile').first().json || {};
const paidLead = $('Mark Lead as Paid').first().json || {};
const profile = normalized.user_profile || {};

const programPlan = planData.program_plan || {};
const weekNum = 1;
const weekKey = 'week_1';
const weekPlan = programPlan[weekKey] || {};

const sessions = ['morning', 'midday', 'afternoon', 'evening'];
const weekPlanForPdf = {};
for (const s of sessions) {
  const slot = weekPlan[s] || {};
  weekPlanForPdf[s] = {
    warmup: slot.warmup ? {
      name: slot.warmup.name,
      description: slot.warmup.description,
      image_url: slot.warmup.image_url || slot.warmup.imageUrl || slot.warmup.image || slot.warmup.photo_url || slot.warmup.photoUrl || '',
      cues: slot.warmup.cues
    } : null,
    main: slot.main ? {
      name: slot.main.name,
      description: slot.main.description,
      image_url: slot.main.image_url || slot.main.imageUrl || slot.main.image || slot.main.photo_url || slot.main.photoUrl || '',
      cues: slot.main.cues
    } : null
  };
}

const calendarMap = {
  1: $env.CALENDAR_WEEK1_URL || '',
  2: $env.CALENDAR_WEEK2_URL || '',
  3: $env.CALENDAR_WEEK3_URL || '',
  4: $env.CALENDAR_WEEK4_URL || ''
};

return [{
  json: {
    name: normalized.name || paidLead.name || 'there',
    email: normalized.email || paidLead.email || '',
    week_number: weekNum,
    template_key: weekKey,
    week_plan: weekPlanForPdf,
    profile,
    calendar_url: calendarMap[weekNum] || $env.CALENDAR_DEFAULT_URL || ''
  }
}];

const payload = $('Build PDF Payload').first().json;
const template = $('Load Email Template').first().json;

const fill = (str, vars) => String(str || '').replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (_, key) => String(vars[key] ?? ''));

const safeName = payload.name || 'there';
const vars = {
  name: safeName,
  Name: safeName,
  week_number: payload.week_number,
  calendar_url: payload.calendar_url || '',
  week_pdf_url: '',
  level2_offer_url: $env.LEVEL2_OFFER_URL || '',
  feedback_url: $env.FEEDBACK_FORM_URL || '',
  checkout_url: '',
  mdt_blog_url: $env.MDT_BLOG_URL || '',
  goal: payload.goal || payload.profile?.primary_goal || payload.profile?.goal || ''
};

return [{
  json: {
    ...payload,
    email_subject: fill(template.subject, vars),
    email_html: fill(template.html, vars),
    attachment_filename: `week${payload.week_number}-plan.pdf`
  }
}];

